const https = require('https');

function nocoRequest(method, path, body) {
  return new Promise((resolve, reject) => {
    const options = {
      hostname: 'nocodb.pressco21.com',
      path: '/api/v1/db/data/noco/' + $env.NOCODB_PROJECT_ID + path,
      method: method,
      headers: {
        'xc-token': $env.NOCODB_API_TOKEN,
        'Content-Type': 'application/json'
      }
    };
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', c => data += c);
      res.on('end', () => {
        try { resolve(JSON.parse(data)); } catch(e) { resolve(data); }
      });
    });
    req.on('error', reject);
    if (body) req.write(JSON.stringify(body));
    req.end();
  });
}

const body = $input.first().json.body || {};
const { member_id, class_id } = body;

try {
  if (!member_id || !class_id) {
    return [{json: {success: false, message: 'member_id and class_id required', statusCode: 400}}];
  }

  // 파트너 인증
  const partners = await nocoRequest('GET', '/mp8t0yq15cabmj4?where=(member_id,eq,' + encodeURIComponent(member_id) + ')~and(status,eq,active)&limit=1');
  if (!partners.list || partners.list.length === 0) {
    return [{json: {success: false, message: 'not an active partner', statusCode: 403}}];
  }
  const partner = partners.list[0];

  // 클래스 소유 확인
  const classes = await nocoRequest('GET', '/mpvsno4or6asbxk?where=(class_id,eq,' + encodeURIComponent(class_id) + ')~and(partner_code,eq,' + encodeURIComponent(partner.partner_code) + ')&limit=1');
  if (!classes.list || classes.list.length === 0) {
    return [{json: {success: false, message: 'class not found or not owned by you', statusCode: 403}}];
  }
  const cls = classes.list[0];

  // 수정 가능 필드만 추출
  const allowedFields = ['class_name', 'description', 'price', 'category', 'level', 'duration_min', 'max_students', 'thumbnail_url', 'image_urls', 'instructor_bio', 'location', 'materials_included', 'youtube_video_id', 'tags', 'kit_enabled', 'kit_items'];
  const updateData = {};
  let hasChanges = false;

  for (const field of allowedFields) {
    if (body[field] !== undefined && body[field] !== null) {
      updateData[field] = body[field];
      hasChanges = true;
    }
  }

  if (!hasChanges) {
    return [{json: {success: false, message: 'no fields to update', statusCode: 400}}];
  }

  // kit_items를 JSON 문자열로 직렬화
  if (updateData.kit_items !== undefined) {
    if (Array.isArray(updateData.kit_items)) {
      updateData.kit_items = JSON.stringify(updateData.kit_items);
    }
  }
  if (updateData.kit_enabled !== undefined) {
    updateData.kit_enabled = Number(updateData.kit_enabled) || 0;
  }

  // price 검증
  if (updateData.price !== undefined) {
    const p = Number(updateData.price);
    if (isNaN(p) || p < 0) {
      return [{json: {success: false, message: 'invalid price', statusCode: 400}}];
    }
    updateData.price = p;
  }

  // NocoDB PATCH
  await nocoRequest('PATCH', '/mpvsno4or6asbxk/' + cls.Id, updateData);

  return [{json: {
    success: true,
    message: 'class updated',
    data: { class_id: class_id, updated_fields: Object.keys(updateData) },
    statusCode: 200
  }}];

} catch(e) {
  return [{json: {success: false, message: 'Internal error: ' + e.message, statusCode: 500}}];
}
